 1	import type { FC } from 'react';
 2	import { useHistory } from 'react-router';
 3	import useGetDeleteAndEditAccessReview from 'src/modules/Providers/hooks/useGetDeleteAndEditAccessReview';
 4	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
 5	import { TELEMETRY_EVENTS } from 'src/utils/analytics/constants';
 6	import { useForkliftAnalytics } from 'src/utils/analytics/hooks/useForkliftAnalytics';
 7	import { useForkliftTranslation } from 'src/utils/i18n';
 8	
 9	import { PlanModel, PlanModelRef, type V1beta1Provider } from '@kubev2v/types';
10	import { Button, ButtonVariant, ToolbarItem } from '@patternfly/react-core';
11	import { getNamespace } from '@utils/crds/common/selectors';
12	
13	type CreatePlanActionProps = {
14	  namespace: string | undefined;
15	  provider?: V1beta1Provider;
16	};
17	
18	const CreatePlanAction: FC<CreatePlanActionProps> = ({ namespace, provider }) => {
19	  const { t } = useForkliftTranslation();
20	  const history = useHistory();
21	  const { trackEvent } = useForkliftAnalytics();
22	
23	  const { canCreate } = useGetDeleteAndEditAccessReview({
24	    model: PlanModel,
25	    namespace,
26	  });
27	
28	  const handleCreatePlan = () => {
29	    trackEvent(TELEMETRY_EVENTS.PLAN_CREATE_FROM_PROVIDER_CLICKED, {
30	      planNamespace: namespace,
31	      providerId: provider?.metadata?.name,
32	      providerNamespace: getNamespace(provider),
33	      providerType: provider?.spec?.type,
34	    });
35	
36	    const planResourceUrl = getResourceUrl({
37	      namespaced: false,
38	      reference: PlanModelRef,
39	    });
40	
41	    history.push({
42	      pathname: `${planResourceUrl}/~new`,
43	      state: {
44	        planProject: provider ? getNamespace(provider) : '',
45	        sourceProvider: provider,
46	      },
47	    });
48	  };
49	
50	  return (
51	    <ToolbarItem>
52	      <Button variant={ButtonVariant.primary} onClick={handleCreatePlan} isDisabled={!canCreate}>
53	        {t('Create migration plan')}
54	      </Button>
55	    </ToolbarItem>
56	  );
57	};
58	
59	export default CreatePlanAction;

